parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "nombre": {
      "type": "string",
      "description": "Nombre completo del lead"
    },
    "email": {
      "type": "string",
      "description": "Correo electrónico de contacto"
    },
    "telefono": {
      "type": "string",
      "description": "Número de teléfono del contacto"
    },
    "materia": {
      "type": "string",
      "description": "Materia que necesita reforzar"
    },
    "nivel": {
      "type": "string",
      "description": "Nivel académico del estudiante (Primaria, Secundaria, Bachillerato, Universidad)"
    },
    "descripcion": {
      "type": "string",
      "description": "Breve descripción de la necesidad académica"
    }
  },
  "required": ["nombre", "email", "telefono", "materia"]
}
